// Embedded Geist + Geist Mono web fonts as base64 woff2 data URLs. Embedding (not URLs) is required
// because the exported HTML must remain fully self-contained — the test forbids external font CDNs.

const GEIST_SANS_400_BASE64 = "";
const GEIST_SANS_500_BASE64 = "";
const GEIST_SANS_600_BASE64 = "";
const GEIST_MONO_400_BASE64 = "";
const GEIST_MONO_500_BASE64 = "";

export function renderEmbeddedGeistFontFaceDeclarations(): string {
  return `@font-face{font-family:'Geist';font-style:normal;font-weight:400;font-display:swap;src:url(data:font/woff2;base64,${GEIST_SANS_400_BASE64}) format('woff2');}@font-face{font-family:'Geist';font-style:normal;font-weight:500;font-display:swap;src:url(data:font/woff2;base64,${GEIST_SANS_500_BASE64}) format('woff2');}@font-face{font-family:'Geist';font-style:normal;font-weight:600;font-display:swap;src:url(data:font/woff2;base64,${GEIST_SANS_600_BASE64}) format('woff2');}@font-face{font-family:'Geist Mono';font-style:normal;font-weight:400;font-display:swap;src:url(data:font/woff2;base64,${GEIST_MONO_400_BASE64}) format('woff2');}@font-face{font-family:'Geist Mono';font-style:normal;font-weight:500;font-display:swap;src:url(data:font/woff2;base64,${GEIST_MONO_500_BASE64}) format('woff2');}`;
}
